async function loadGatewayUser(req, res, next) {
  try {
    if (!req.session?.userId) return next();

    const user = await db.findUser(req.session.userId);
    if (!user) return next();

    await flags.load(user);
    await audit.log(req, user);

    req.gatewayUser = user;
    next();
  } catch (err) {
    next(err);
  }
}
```

**Changes:**

- `async` keyword on function signature
- `await` replaces callback chains for `db.findUser`, `flags.load`, `audit.log`
- `try/catch` funnels errors to `next(err)`
- Order preserved: `session_check` → `db.findUser` → `flags.load` → `audit.log` → `next`
- Minimal surface change; same middleware signature `(req, res, next)`
